import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum UserRole {
  USER = 'user',
  ADMIN = 'admin',
}

export interface User {
  id: string;
  username: string;
  email: string;
  role: UserRole;
  token?: string;
}

export interface Episode {
  id: string;
  number: number;
  title: string;
  videoUrl: string; // URL to the video file or embed
}

export interface Anime {
  id: string;
  title: string;
  description: string;
  coverImage: string; // URL
  genres: string[];
  episodes: Episode[];
  createdAt: string;
}

export interface AuthResponse {
  user: User;
  token: string;
}

import { Anime, AuthResponse, User, UserRole } from '../types';

// Constants for LocalStorage keys
const USERS_KEY = 'anipal_users';
const ANIMES_KEY = 'anipal_animes';
const CURRENT_USER_KEY = 'anipal_current_user';

// Initial Admin Seed
const INITIAL_ADMIN = {
  id: 'admin-1',
  username: 'heblebi',
  email: 'heblebi@anipal.com',
  passwordHash: '123456', // In a real app, this would be bcrypt hash
  role: UserRole.ADMIN,
};

// Initial Anime Seed
const INITIAL_ANIMES: Anime[] = [
  {
    id: 'anime-1',
    title: 'Cyber Runner: Edge',
    description: 'In a dystopian future, a street kid tries to survive in a technology-obsessed city where body modification is the obsession. He decides to become a mercenary outlaw known as an edge runner.',
    coverImage: 'https://picsum.photos/seed/cyber/300/450',
    genres: ['Action', 'Sci-Fi', 'Psychological'],
    episodes: [
      { id: 'ep-1', number: 1, title: 'Wake Up', videoUrl: 'https://media.w3.org/2010/05/sintel/trailer_hd.mp4' },
      { id: 'ep-2', number: 2, title: 'The Job', videoUrl: 'https://media.w3.org/2010/05/sintel/trailer_hd.mp4' },
    ],
    createdAt: new Date().toISOString(),
  },
  {
    id: 'anime-2',
    title: 'Spirit Hunter',
    description: 'A young boy discovers he is part of a long lineage of spirit hunters charged with protecting the human world from the unseen demons that lurk in the shadows.',
    coverImage: 'https://picsum.photos/seed/spirit/300/450',
    genres: ['Adventure', 'Supernatural', 'Shonen'],
    episodes: [
        { id: 'ep-1', number: 1, title: 'The Beginning', videoUrl: 'https://media.w3.org/2010/05/sintel/trailer_hd.mp4' }
    ],
    createdAt: new Date().toISOString(),
  }
];

// Helper to simulate network delay
const delay = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms));

// Initialize Mock Database
const initializeDB = () => {
  if (!localStorage.getItem(USERS_KEY)) {
    localStorage.setItem(USERS_KEY, JSON.stringify([INITIAL_ADMIN]));
  }
  if (!localStorage.getItem(ANIMES_KEY)) {
    localStorage.setItem(ANIMES_KEY, JSON.stringify(INITIAL_ANIMES));
  }
};

initializeDB();

// --- Auth Services ---

export const login = async (emailOrUsername: string, password: string): Promise<AuthResponse> => {
  await delay(500); // Simulate network latency
  const users = JSON.parse(localStorage.getItem(USERS_KEY) || '[]');

  const user = users.find((u: any) => 
    (u.email === emailOrUsername || u.username === emailOrUsername) && u.passwordHash === password
  );

  if (!user) {
    throw new Error('Invalid credentials');
  }

  // Generate a fake JWT
  const token = `fake-jwt-token-${user.id}-${Date.now()}`;
  const safeUser: User = { id: user.id, username: user.username, email: user.email, role: user.role };

  // Persist session
  localStorage.setItem(CURRENT_USER_KEY, JSON.stringify({ ...safeUser, token }));

  return { user: safeUser, token };
};

export const register = async (username: string, email: string, password: string): Promise<AuthResponse> => {
  await delay(500);
  const users = JSON.parse(localStorage.getItem(USERS_KEY) || '[]');

  if (users.find((u: any) => u.email === email)) {
    throw new Error('Email already exists');
  }

  const newUser = {
    id: `user-${Date.now()}`,
    username,
    email,
    passwordHash: password, // In production: bcrypt.hash(password, 10)
    role: UserRole.USER,
  };

  users.push(newUser);
  localStorage.setItem(USERS_KEY, JSON.stringify(users));

  const token = `fake-jwt-token-${newUser.id}-${Date.now()}`;
  const safeUser: User = { id: newUser.id, username: newUser.username, email: newUser.email, role: newUser.role };

  localStorage.setItem(CURRENT_USER_KEY, JSON.stringify({ ...safeUser, token }));

  return { user: safeUser, token };
};

export const logout = async () => {
  localStorage.removeItem(CURRENT_USER_KEY);
};

export const getCurrentUser = (): User | null => {
  const stored = localStorage.getItem(CURRENT_USER_KEY);
  return stored ? JSON.parse(stored) : null;
};

// --- Anime Services ---

export const getAnimes = async (): Promise<Anime[]> => {
  await delay(300);
  return JSON.parse(localStorage.getItem(ANIMES_KEY) || '[]');
};

export const getAnimeById = async (id: string): Promise<Anime | undefined> => {
  await delay(200);
  const animes = JSON.parse(localStorage.getItem(ANIMES_KEY) || '[]');
  return animes.find((a: Anime) => a.id === id);
};

export const createAnime = async (animeData: Omit<Anime, 'id' | 'createdAt' | 'episodes'>): Promise<Anime> => {
  await delay(600);
  const animes = JSON.parse(localStorage.getItem(ANIMES_KEY) || '[]');

  const newAnime: Anime = {
    ...animeData,
    id: `anime-${Date.now()}`,
    createdAt: new Date().toISOString(),
    episodes: [],
  };

  animes.push(newAnime);
  localStorage.setItem(ANIMES_KEY, JSON.stringify(animes));
  return newAnime;
};

export const addEpisode = async (animeId: string, episodeData: Omit<Episode, 'id'>): Promise<Anime> => {
    await delay(400);
    const animes = JSON.parse(localStorage.getItem(ANIMES_KEY) || '[]');
    const animeIndex = animes.findIndex((a: Anime) => a.id === animeId);

    if (animeIndex === -1) throw new Error("Anime not found");

    const newEpisode: Episode = {
        ...episodeData,
        id: `ep-${Date.now()}`,
    };

    animes[animeIndex].episodes.push(newEpisode);
    // Sort by episode number
    animes[animeIndex].episodes.sort((a: Episode, b: Episode) => a.number - b.number);

    localStorage.setItem(ANIMES_KEY, JSON.stringify(animes));
    return animes[animeIndex];
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { User } from '../types';
import { getCurrentUser, logout as apiLogout } from '../services/mockBackend';

interface AuthContextType {
  user: User | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  loginUser: (user: User) => void;
  logoutUser: () => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider = ({ children }: { children: ReactNode }) => {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    // Check for persisted session on mount
    const checkAuth = async () => {
      try {
        const currentUser = getCurrentUser();
        if (currentUser) {
          setUser(currentUser);
        }
      } catch (error) {
        console.error("Auth restoration failed", error);
      } finally {
        setIsLoading(false);
      }
    };
    checkAuth();
  }, []);

  const loginUser = (userData: User) => {
    setUser(userData);
  };

  const logoutUser = async () => {
    await apiLogout();
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ 
      user, 
      isAuthenticated: !!user, 
      isLoading, 
      loginUser, 
      logoutUser 
    }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  isLoading?: boolean;
}

const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  className = '', 
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center px-4 py-2 rounded-lg font-medium transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-amber-500 hover:bg-amber-600 text-black focus:ring-amber-500",
    secondary: "bg-gray-800 hover:bg-gray-700 text-white border border-gray-700 focus:ring-gray-500",
    danger: "bg-red-600 hover:bg-red-700 text-white focus:ring-red-500",
    ghost: "bg-transparent hover:bg-gray-800 text-gray-300 hover:text-white"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${className}`}
      disabled={isLoading || props.disabled}
      {...props}
    >
      {isLoading ? (
        <svg className="animate-spin -ml-1 mr-2 h-5 w-5" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
        </svg>
      ) : null}
      {children}
    </button>
  );
};

export default Button;

import React from 'react';

interface InputProps extends React.InputHTMLAttributes<HTMLInputElement> {
