    logoutUser();
  };

  const isActive = (path: string) => location.pathname === path ? 'text-amber-500' : 'text-gray-300 hover:text-white';

  return (
    <div className="min-h-screen bg-[#0f0f10] text-gray-100 flex flex-col">
      {/* Navbar */}
      <nav className="border-b border-gray-800 bg-[#18181b]/90 backdrop-blur-sm sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex items-center justify-between h-16">

            {/* Brand */}
            <div className="flex items-center">
              <Link to="/" className="flex items-center space-x-2">
                <div className="w-8 h-8 bg-amber-500 rounded flex items-center justify-center">
                  <Film className="w-5 h-5 text-black" />
                </div>
                <span className="text-xl font-bold tracking-tight text-amber-500">ANIPAL</span>
              </Link>
            </div>

            {/* Desktop Nav */}
            <div className="hidden md:flex items-center space-x-8">
              <Link to="/" className={`font-medium transition-colors ${isActive('/')}`}>Home</Link>
              {user?.role === UserRole.ADMIN && (
                <Link to="/admin" className={`flex items-center gap-1 font-medium transition-colors ${isActive('/admin')}`}>
                  <PlusCircle size={16} /> Admin
                </Link>
              )}
            </div>

            {/* Desktop Auth */}
            <div className="hidden md:flex items-center space-x-4">
              {isAuthenticated && user ? (
                <div className="flex items-center space-x-4">
