            </div>
          </div>
        </div>

        {/* Mobile Menu */}
        {isMobileMenuOpen && (
          <div className="md:hidden bg-[#18181b] border-b border-gray-800">
            <div className="px-4 pt-2 pb-4 space-y-1">
              <Link to="/" className="block px-3 py-2 text-base font-medium text-white hover:bg-gray-800 rounded-md">Home</Link>
              {user?.role === UserRole.ADMIN && (
                <Link to="/admin" className="block px-3 py-2 text-base font-medium text-white hover:bg-gray-800 rounded-md">Admin Dashboard</Link>
              )}

              <div className="border-t border-gray-800 my-2 pt-2">
                {isAuthenticated ? (
