                     <div className="px-3 py-2 text-sm text-gray-400">Signed in as {user?.username}</div>
                     <button onClick={handleLogout} className="w-full text-left px-3 py-2 text-base font-medium text-red-400 hover:bg-gray-800 rounded-md">
