                    <Link to="/login" className="block w-full text-center px-3 py-2 bg-gray-800 rounded-md">Login</Link>
                    <Link to="/register" className="block w-full text-center px-3 py-2 bg-amber-500 text-black font-bold rounded-md">Sign Up</Link>
