import React, { useEffect, useState } from 'react';
import { getAnimes } from '../services/mockBackend';
import { Anime } from '../types';
import AnimeCard from '../components/AnimeCard';

const Home = () => {
  const [animes, setAnimes] = useState<Anime[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const fetchAnimes = async () => {
      try {
        const data = await getAnimes();
        setAnimes(data);
      } catch (error) {
        console.error("Failed to load animes", error);
      } finally {
        setIsLoading(false);
      }
    };

    fetchAnimes();
  }, []);

  if (isLoading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-amber-500"></div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-3xl font-bold text-white">Popular Anime</h2>
        <div className="text-sm text-gray-400">{animes.length} titles available</div>
      </div>

      {animes.length === 0 ? (
        <div className="text-center py-20 text-gray-500">
          No anime found. An admin needs to add some!
        </div>
      ) : (
        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-6">
          {animes.map((anime) => (
            <AnimeCard key={anime.id} anime={anime} />
          ))}
        </div>
      )}
    </div>
  );
};

export default Home;

import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { getAnimeById } from '../services/mockBackend';
import { Anime, Episode } from '../types';
import Button from '../components/Button';
import { PlayCircle, List } from 'lucide-react';

const AnimeDetail = () => {
  const { id } = useParams<{ id: string }>();
  const [anime, setAnime] = useState<Anime | null>(null);
  const [loading, setLoading] = useState(true);
  const [selectedEpisode, setSelectedEpisode] = useState<Episode | null>(null);

  useEffect(() => {
    const fetchAnime = async () => {
      if (id) {
        const data = await getAnimeById(id);
        if (data) {
          setAnime(data);
          if (data.episodes.length > 0) {
            setSelectedEpisode(data.episodes[0]);
          }
        }
      }
      setLoading(false);
    };
    fetchAnime();
  }, [id]);

  if (loading) return <div className="text-center p-10">Loading...</div>;
  if (!anime) return <div className="text-center p-10">Anime not found</div>;

  return (
    <div className="space-y-8">
      {/* Video Player Section */}
      <div className="w-full bg-black rounded-xl overflow-hidden shadow-2xl border border-gray-800">
        {selectedEpisode ? (
          <div className="aspect-video w-full relative">
            <video 
              key={selectedEpisode.id} // Force re-render on episode change
              controls 
              className="w-full h-full object-contain"
              src={selectedEpisode.videoUrl} 
              poster={anime.coverImage}
            >
              Your browser does not support the video tag.
            </video>
          </div>
        ) : (
          <div className="aspect-video flex items-center justify-center bg-gray-900 text-gray-500">
            No episodes available yet.
          </div>
        )}
        <div className="p-4 bg-[#18181b]">
          <h1 className="text-xl font-bold text-amber-500">
            {selectedEpisode ? `Ep ${selectedEpisode.number}: ${selectedEpisode.title}` : 'Select an Episode'}
          </h1>
        </div>
      </div>

      {/* Info & Episodes Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Info Column */}
        <div className="lg:col-span-1 space-y-4">
          <img 
            src={anime.coverImage} 
            alt={anime.title} 
            className="w-full rounded-xl shadow-lg border border-gray-800" 
          />
          <div>
            <h2 className="text-2xl font-bold mb-2">{anime.title}</h2>
            <div className="flex flex-wrap gap-2 mb-4">
              {anime.genres.map(g => (
                <span key={g} className="text-xs font-bold px-2 py-1 bg-gray-800 text-amber-500 rounded border border-gray-700">
                  {g}
                </span>
              ))}
            </div>
            <p className="text-gray-400 leading-relaxed text-sm">
              {anime.description}
            </p>
          </div>
        </div>

        {/* Episode List Column */}
        <div className="lg:col-span-2">
           <div className="flex items-center gap-2 mb-4 border-b border-gray-800 pb-2">
             <List className="text-amber-500" />
             <h3 className="text-xl font-bold">Episodes</h3>
           </div>

           <div className="grid grid-cols-1 gap-2 max-h-[500px] overflow-y-auto pr-2">
             {anime.episodes.length > 0 ? (
               anime.episodes.map((ep) => (
                 <button
                   key={ep.id}
                   onClick={() => setSelectedEpisode(ep)}
                   className={`flex items-center p-3 rounded-lg transition-all text-left group ${
                     selectedEpisode?.id === ep.id 
                       ? 'bg-amber-500 text-black shadow-lg shadow-amber-500/20' 
                       : 'bg-gray-800/50 hover:bg-gray-800 text-gray-300'
                   }`}
                 >
                    <PlayCircle className={`mr-3 w-5 h-5 ${selectedEpisode?.id === ep.id ? 'text-black' : 'text-amber-500 group-hover:scale-110 transition-transform'}`} />
                    <div>
                      <span className="font-bold mr-2">Episode {ep.number}</span>
                      <span className="opacity-80 text-sm">{ep.title}</span>
                    </div>
                 </button>
               ))
             ) : (
                <p className="text-gray-500 italic">No episodes uploaded yet.</p>
             )}
           </div>
        </div>

      </div>
    </div>
  );
};

export default AnimeDetail;

import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { UserRole, Anime } from '../types';
import { useNavigate } from 'react-router-dom';
import Input from '../components/Input';
import Button from '../components/Button';
import { createAnime, addEpisode, getAnimes } from '../services/mockBackend';

const AdminDashboard = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'create' | 'episode'>('create');
  const [animes, setAnimes] = useState<Anime[]>([]);

  // Anime Form State
  const [title, setTitle] = useState('');
  const [desc, setDesc] = useState('');
  const [cover, setCover] = useState('');
  const [genres, setGenres] = useState('');

  // Episode Form State
  const [selectedAnimeId, setSelectedAnimeId] = useState('');
  const [epTitle, setEpTitle] = useState('');
  const [epNumber, setEpNumber] = useState('');
  const [videoUrl, setVideoUrl] = useState('');

  const [loading, setLoading] = useState(false);
  const [msg, setMsg] = useState<{type: 'success'|'error', text: string} | null>(null);

  useEffect(() => {
    if (!user || user.role !== UserRole.ADMIN) {
      navigate('/');
    }
    loadAnimes();
  }, [user, navigate]);

  const loadAnimes = async () => {
    const data = await getAnimes();
    setAnimes(data);
  };

  const handleCreateAnime = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setMsg(null);
    try {
      await createAnime({
        title,
        description: desc,
        coverImage: cover,
        genres: genres.split(',').map(g => g.trim()),
      });
      setMsg({ type: 'success', text: 'Anime created successfully!' });
      setTitle(''); setDesc(''); setCover(''); setGenres('');
      loadAnimes();
    } catch (err) {
      setMsg({ type: 'error', text: 'Failed to create anime' });
    } finally {
      setLoading(false);
    }
  };

  const handleAddEpisode = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setMsg(null);
    try {
      if(!selectedAnimeId) throw new Error("Select an anime");
      await addEpisode(selectedAnimeId, {
        title: epTitle,
        number: parseInt(epNumber),
        videoUrl
      });
      setMsg({ type: 'success', text: 'Episode added successfully!' });
      setEpTitle(''); setEpNumber(''); setVideoUrl('');
    } catch (err: any) {
        setMsg({ type: 'error', text: err.message || 'Failed to add episode' });
    } finally {
        setLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto space-y-8">
      <div className="bg-gray-900 p-6 rounded-xl border border-gray-800">
        <h1 className="text-3xl font-bold text-amber-500 mb-6">Admin Dashboard</h1>

        {/* Tabs */}
        <div className="flex border-b border-gray-700 mb-6">
          <button 
            className={`px-4 py-2 font-medium ${activeTab === 'create' ? 'text-amber-500 border-b-2 border-amber-500' : 'text-gray-400'}`}
            onClick={() => setActiveTab('create')}
          >
            Create Anime
          </button>
          <button 
            className={`px-4 py-2 font-medium ${activeTab === 'episode' ? 'text-amber-500 border-b-2 border-amber-500' : 'text-gray-400'}`}
            onClick={() => setActiveTab('episode')}
          >
            Add Episode
          </button>
        </div>

        {msg && (
          <div className={`p-4 rounded mb-4 ${msg.type === 'success' ? 'bg-green-900/50 text-green-300' : 'bg-red-900/50 text-red-300'}`}>
            {msg.text}
          </div>
        )}

        {activeTab === 'create' ? (
          <form onSubmit={handleCreateAnime} className="space-y-4">
            <Input label="Title" value={title} onChange={e => setTitle(e.target.value)} required />
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-1">Description</label>
              <textarea 
                className="w-full px-4 py-2 bg-gray-800 border border-gray-700 rounded-lg text-white focus:ring-2 focus:ring-amber-500 h-24"
                value={desc} 
                onChange={e => setDesc(e.target.value)} 
                required
              />
            </div>
            <Input label="Cover Image URL" value={cover} onChange={e => setCover(e.target.value)} placeholder="https://..." required />
            <Input label="Genres (comma separated)" value={genres} onChange={e => setGenres(e.target.value)} placeholder="Action, Drama, Sci-Fi" required />

            <Button type="submit" isLoading={loading} className="w-full">Create Anime</Button>
          </form>
        ) : (
          <form onSubmit={handleAddEpisode} className="space-y-4">
            <div>
               <label className="block text-sm font-medium text-gray-300 mb-1">Select Anime</label>
               <select 
                  className="w-full px-4 py-2 bg-gray-800 border border-gray-700 rounded-lg text-white"
                  value={selectedAnimeId}
                  onChange={e => setSelectedAnimeId(e.target.value)}
                  required
               >
                  <option value="">-- Choose Anime --</option>
                  {animes.map(a => <option key={a.id} value={a.id}>{a.title}</option>)}
               </select>
            </div>
            <div className="grid grid-cols-2 gap-4">
                <Input label="Episode Number" type="number" value={epNumber} onChange={e => setEpNumber(e.target.value)} required />
                <Input label="Episode Title" value={epTitle} onChange={e => setEpTitle(e.target.value)} required />
            </div>
            <Input label="Video URL" value={videoUrl} onChange={e => setVideoUrl(e.target.value)} placeholder="https://...mp4" required />

            <Button type="submit" isLoading={loading} className="w-full">Add Episode</Button>
          </form>
        )}
      </div>
    </div>
  );
};

export default AdminDashboard;

