// Constants for LocalStorage keys
const USERS_KEY = 'anipal_users';
const ANIMES_KEY = 'anipal_animes';
const CURRENT_USER_KEY = 'anipal_current_user';

// Initial Admin Seed
const INITIAL_ADMIN = {
