import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { getAnimeById } from '../services/mockBackend';
import { Anime, Episode } from '../types';
import VideoPlayer from '../components/VideoPlayer';
import { PlayCircle, List, Info } from 'lucide-react';

const AnimeDetail = () => {
  const { id } = useParams<{ id: string }>();
  const [anime, setAnime] = useState<Anime | null>(null);
  const [loading, setLoading] = useState(true);
  const [selectedEpisode, setSelectedEpisode] = useState<Episode | null>(null);

  useEffect(() => {
    const fetchAnime = async () => {
      if (id) {
        const data = await getAnimeById(id);
        if (data) {
          setAnime(data);
          if (data.episodes.length > 0) {
            setSelectedEpisode(data.episodes[0]);
          }
        }
      }
      setLoading(false);
    };
    fetchAnime();
  }, [id]);

  if (loading) return <div className="text-center p-10 text-amber-500">Yükleniyor...</div>;
  if (!anime) return <div className="text-center p-10 text-red-500">Anime bulunamadı</div>;

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* Video Player Section */}
      <div className="w-full">
        {selectedEpisode ? (
          <div className="space-y-4">
             <VideoPlayer embedUrl={selectedEpisode.videoUrl} poster={anime.coverImage} />
             <div className="p-4 bg-[#18181b] rounded-xl border border-gray-800">
