                    </span>
                    <h1 className="text-xl font-bold text-white">
                        {selectedEpisode.title}
                    </h1>
                </div>
             </div>
          </div>
        ) : (
          <div className="aspect-video flex flex-col items-center justify-center bg-gray-900 text-gray-500 rounded-xl border border-gray-800">
            <Info size={48} className="mb-4 opacity-50" />
            <p>Bu anime için henüz bölüm yüklenmemiş.</p>
