      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Info Column */}
        <div className="lg:col-span-1 space-y-4">
          <div className="rounded-xl overflow-hidden shadow-2xl border border-gray-800 group">
              <img 
                src={anime.coverImage} 
                alt={anime.title} 
                className="w-full object-cover transition-transform duration-500 group-hover:scale-105" 
              />
          </div>
          <div className="bg-[#18181b] p-4 rounded-xl border border-gray-800">
            <h2 className="text-2xl font-bold mb-3 text-white">{anime.title}</h2>
            <div className="flex flex-wrap gap-2 mb-4">
