              ))}
            </div>
            <p className="text-gray-400 leading-relaxed text-sm">
              {anime.description}
            </p>
          </div>
        </div>

        {/* Episode List Column */}
        <div className="lg:col-span-2">
           <div className="bg-[#18181b] rounded-xl border border-gray-800 p-4 h-full">
               <div className="flex items-center gap-2 mb-4 border-b border-gray-700 pb-3">
                 <List className="text-amber-500" />
                 <h3 className="text-xl font-bold">Bölümler</h3>
                 <span className="ml-auto text-xs text-gray-500">{anime.episodes.length} Bölüm</span>
