import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { UserRole, Anime } from '../types';
import { useNavigate } from 'react-router-dom';
import Input from '../components/Input';
import Button from '../components/Button';
import { createAnime, addEpisode, getAnimes } from '../services/mockBackend';

const AdminDashboard = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [activeTab, setActiveTab] = useState<'create' | 'episode'>('create');
  const [animes, setAnimes] = useState<Anime[]>([]);

  // Anime Form State
  const [title, setTitle] = useState('');
  const [desc, setDesc] = useState('');
  const [cover, setCover] = useState('');
  const [genres, setGenres] = useState('');

  // Episode Form State
  const [selectedAnimeId, setSelectedAnimeId] = useState('');
  const [epTitle, setEpTitle] = useState('');
  const [epNumber, setEpNumber] = useState('');
  const [videoUrl, setVideoUrl] = useState('');

  const [loading, setLoading] = useState(false);
  const [msg, setMsg] = useState<{type: 'success'|'error', text: string} | null>(null);

  useEffect(() => {
    if (!user || user.role !== UserRole.ADMIN) {
      navigate('/');
    }
    loadAnimes();
  }, [user, navigate]);

  const loadAnimes = async () => {
    const data = await getAnimes();
    setAnimes(data);
  };

  const handleCreateAnime = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setMsg(null);
    try {
      await createAnime({
        title,
        description: desc,
        coverImage: cover,
        genres: genres.split(',').map(g => g.trim()),
      });
      setMsg({ type: 'success', text: 'Anime başarıyla oluşturuldu!' });
      setTitle(''); setDesc(''); setCover(''); setGenres('');
      loadAnimes();
    } catch (err) {
      setMsg({ type: 'error', text: 'Anime oluşturulamadı.' });
    } finally {
      setLoading(false);
    }
  };

  const handleAddEpisode = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setMsg(null);
    try {
      if(!selectedAnimeId) throw new Error("Lütfen bir anime seçin");
      await addEpisode(selectedAnimeId, {
        title: epTitle,
        number: parseInt(epNumber),
        videoUrl // Now expected to be an embed URL
      });
      setMsg({ type: 'success', text: 'Bölüm başarıyla eklendi!' });
      setEpTitle(''); setEpNumber(''); setVideoUrl('');
    } catch (err: any) {
        setMsg({ type: 'error', text: err.message || 'Bölüm eklenemedi.' });
    } finally {
        setLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto space-y-8">
      <div className="bg-gray-900 p-6 rounded-xl border border-gray-800 shadow-2xl">
        <h1 className="text-3xl font-bold text-amber-500 mb-6 flex items-center gap-2">
             Admin Paneli
        </h1>

        {/* Tabs */}
        <div className="flex border-b border-gray-700 mb-6">
          <button 
            className={`px-4 py-2 font-medium transition-colors ${activeTab === 'create' ? 'text-amber-500 border-b-2 border-amber-500' : 'text-gray-400 hover:text-white'}`}
            onClick={() => setActiveTab('create')}
          >
            Anime Oluştur
          </button>
          <button 
            className={`px-4 py-2 font-medium transition-colors ${activeTab === 'episode' ? 'text-amber-500 border-b-2 border-amber-500' : 'text-gray-400 hover:text-white'}`}
            onClick={() => setActiveTab('episode')}
          >
            Bölüm Ekle
          </button>
        </div>

        {msg && (
          <div className={`p-4 rounded mb-4 text-sm font-medium ${msg.type === 'success' ? 'bg-green-900/50 text-green-300 border border-green-800' : 'bg-red-900/50 text-red-300 border border-red-800'}`}>
            {msg.text}
          </div>
        )}

        {activeTab === 'create' ? (
          <form onSubmit={handleCreateAnime} className="space-y-4">
            <Input label="Anime Başlığı" value={title} onChange={e => setTitle(e.target.value)} required placeholder="Örn: Cyberpunk: Edgerunners" />
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-1">Açıklama</label>
              <textarea 
                className="w-full px-4 py-2 bg-gray-800 border border-gray-700 rounded-lg text-white focus:ring-2 focus:ring-amber-500 h-24 placeholder-gray-500"
                value={desc} 
                onChange={e => setDesc(e.target.value)} 
                required
                placeholder="Anime konusunu buraya yazın..."
              />
            </div>
            <Input label="Kapak Görseli URL" value={cover} onChange={e => setCover(e.target.value)} placeholder="https://..." required />
            <Input label="Türler (Virgülle ayırın)" value={genres} onChange={e => setGenres(e.target.value)} placeholder="Aksiyon, Dram, Bilim Kurgu" required />

            <Button type="submit" isLoading={loading} className="w-full">Animeyi Kaydet</Button>
          </form>
        ) : (
          <form onSubmit={handleAddEpisode} className="space-y-4">
            <div>
               <label className="block text-sm font-medium text-gray-300 mb-1">Anime Seç</label>
               <select 
                  className="w-full px-4 py-2 bg-gray-800 border border-gray-700 rounded-lg text-white focus:outline-none focus:ring-2 focus:ring-amber-500"
                  value={selectedAnimeId}
                  onChange={e => setSelectedAnimeId(e.target.value)}
                  required
               >
                  <option value="">-- Listeden Seçin --</option>
                  {animes.map(a => <option key={a.id} value={a.id}>{a.title}</option>)}
               </select>
            </div>
            <div className="grid grid-cols-2 gap-4">
                <Input label="Bölüm Numarası" type="number" value={epNumber} onChange={e => setEpNumber(e.target.value)} required placeholder="1" />
                <Input label="Bölüm Başlığı" value={epTitle} onChange={e => setEpTitle(e.target.value)} required placeholder="Örn: Başlangıç" />
            </div>
            <Input 
                label="Video Embed Linki (Iframe Src)" 
                value={videoUrl} 
                onChange={e => setVideoUrl(e.target.value)} 
                placeholder="https://www.youtube.com/embed/..." 
                required 
            />
            <p className="text-xs text-gray-500 -mt-3 mb-2">
                Not: Buraya direkt video dosyası değil, embed (gömme) linki yapıştırın (örn: Youtube Embed, Sibnet embed vb.)
            </p>

            <Button type="submit" isLoading={loading} className="w-full">Bölümü Ekle</Button>
          </form>
        )}
      </div>
    </div>
  );
};

export default AdminDashboard;

