export const login = async (emailOrUsername: string, password: string): Promise<AuthResponse> => {
  await delay(500); // Simulate network latency
  const users = JSON.parse(localStorage.getItem(USERS_KEY) || '[]');

  const user = users.find((u: any) => 
    (u.email === emailOrUsername || u.username === emailOrUsername) && u.passwordHash === password
  );

  if (!user) {
    throw new Error('Geçersiz kullanıcı adı veya şifre');
  }

  // Generate a fake JWT
  const token = `fake-jwt-token-${user.id}-${Date.now()}`;
  const safeUser: User = { id: user.id, username: user.username, email: user.email, role: user.role };

  // Persist session
  localStorage.setItem(CURRENT_USER_KEY, JSON.stringify({ ...safeUser, token }));

  return { user: safeUser, token };
};

export const register = async (username: string, email: string, password: string): Promise<AuthResponse> => {
  await delay(500);
  const users = JSON.parse(localStorage.getItem(USERS_KEY) || '[]');

  if (users.find((u: any) => u.email === email)) {
    throw new Error('Bu e-posta adresi zaten kullanımda');
  }

  const newUser = {
    id: `user-${Date.now()}`,
    username,
    email,
    passwordHash: password, // In production: bcrypt.hash(password, 10)
    role: UserRole.USER,
  };

  users.push(newUser);
  localStorage.setItem(USERS_KEY, JSON.stringify(users));

  const token = `fake-jwt-token-${newUser.id}-${Date.now()}`;
  const safeUser: User = { id: newUser.id, username: newUser.username, email: newUser.email, role: newUser.role };

  localStorage.setItem(CURRENT_USER_KEY, JSON.stringify({ ...safeUser, token }));

  return { user: safeUser, token };
};

export const logout = async () => {
  localStorage.removeItem(CURRENT_USER_KEY);
};

export const getCurrentUser = (): User | null => {
  const stored = localStorage.getItem(CURRENT_USER_KEY);
  return stored ? JSON.parse(stored) : null;
};

// --- Anime Services ---

export const getAnimes = async (): Promise<Anime[]> => {
  await delay(300);
  return JSON.parse(localStorage.getItem(ANIMES_KEY) || '[]');
};

export const getAnimeById = async (id: string): Promise<Anime | undefined> => {
  await delay(200);
  const animes = JSON.parse(localStorage.getItem(ANIMES_KEY) || '[]');
  return animes.find((a: Anime) => a.id === id);
};

export const createAnime = async (animeData: Omit<Anime, 'id' | 'createdAt' | 'episodes'>): Promise<Anime> => {
  await delay(600);
  const animes = JSON.parse(localStorage.getItem(ANIMES_KEY) || '[]');

  const newAnime: Anime = {
    ...animeData,
    id: `anime-${Date.now()}`,
    createdAt: new Date().toISOString(),
    episodes: [],
  };

  animes.push(newAnime);
  localStorage.setItem(ANIMES_KEY, JSON.stringify(animes));
  return newAnime;
};

export const addEpisode = async (animeId: string, episodeData: Omit<Episode, 'id'>): Promise<Anime> => {
    await delay(400);
    const animes = JSON.parse(localStorage.getItem(ANIMES_KEY) || '[]');
    const animeIndex = animes.findIndex((a: Anime) => a.id === animeId);

    if (animeIndex === -1) throw new Error("Anime bulunamadı");

    const newEpisode: Episode = {
        ...episodeData,
        id: `ep-${Date.now()}`,
    };

    animes[animeIndex].episodes.push(newEpisode);
    // Sort by episode number
    animes[animeIndex].episodes.sort((a: Episode, b: Episode) => a.number - b.number);

    localStorage.setItem(ANIMES_KEY, JSON.stringify(animes));
    return animes[animeIndex];
};

import React from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Layout from './components/Layout';
import Home from './pages/Home';
import Login from './pages/Login';
import Register from './pages/Register';
import AnimeDetail from './pages/AnimeDetail';
import AdminDashboard from './pages/AdminDashboard';
import { AuthProvider, useAuth } from './context/AuthContext';

// Protected Route Wrapper
const ProtectedRoute = ({ children, requireAdmin }: { children?: React.ReactNode, requireAdmin?: boolean }) => {
  const { user, isAuthenticated, isLoading } = useAuth();

  if (isLoading) return null;

  if (!isAuthenticated) {
    return <Navigate to="/login" />;
  }

  if (requireAdmin && user?.role !== 'admin') {
    return <Navigate to="/" />;
  }

  return <>{children}</>;
};

const AppRoutes = () => {
  return (
    <Routes>
      <Route path="/" element={<Home />} />
      <Route path="/login" element={<Login />} />
      <Route path="/register" element={<Register />} />
      <Route path="/anime/:id" element={<AnimeDetail />} />
      <Route 
        path="/admin" 
        element={
          <ProtectedRoute requireAdmin>
            <AdminDashboard />
          </ProtectedRoute>
        } 
      />
    </Routes>
  );
};

const App = () => {
  return (
    <AuthProvider>
      <HashRouter>
        <Layout>
          <AppRoutes />
        </Layout>
      </HashRouter>
    </AuthProvider>
  );
};

export default App;

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { User } from '../types';
import { getCurrentUser, logout as apiLogout } from '../services/mockBackend';

interface AuthContextType {
  user: User | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  loginUser: (user: User) => void;
  logoutUser: () => void;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider = ({ children }: { children?: ReactNode }) => {
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    // Check for persisted session on mount
    const checkAuth = async () => {
      try {
        const currentUser = getCurrentUser();
        if (currentUser) {
          setUser(currentUser);
        }
      } catch (error) {
        console.error("Auth restoration failed", error);
      } finally {
        setIsLoading(false);
      }
    };
    checkAuth();
  }, []);

  const loginUser = (userData: User) => {
    setUser(userData);
  };

  const logoutUser = async () => {
    await apiLogout();
    setUser(null);
  };

  return (
    <AuthContext.Provider value={{ 
      user, 
      isAuthenticated: !!user, 
      isLoading, 
      loginUser, 
      logoutUser 
    }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

